#pragma once\\n#include <cstdint>\\n#include <cstddef>\\n\\n// Re-export to match expected interface without namespace mismatch\\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\n    size_t N = M * K * K;\\n    if (N == 0 || K == 0) return;\\n\\n    // Process whole blocks of 32 for better cache locality\\n    for (size_t i = 0; i < M; i += 32) {\\n        for (size_t j = 0; j < K; j += 32) {\\n            __m256 rowA = _mm_loadu_ps(A + i * K + j);\\n            __m256 result = _MV_rollup_ps(rowA, _MM_SHOCKMASK_PS(1, __m256__builtin_constant1f((float)j)));\n            // ... (simplified for clarity)\\n            // Store back partial results (simplified, full implementation needed)\n            _mm_storeu_ps(C + i * K + j, _mm_cvtt_psd_ps(result, _MM_SET1_PS(-2.0f)));\\n        }\n    }\\n}